18:   Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
19:     return Http::FilterDataStatus::Continue;
20:   }
21:   Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
22:     return Http::FilterTrailersStatus::Continue;
23:   }
24:   void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
25:     decoder_callbacks_ = &callbacks;
26:   }
27: 
28: protected:
29:   Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
30: };
31: 
32: // An encoder filter which passes all data through with Continue status.
33: class PassThroughEncoderFilter : public virtual StreamEncoderFilter {
34: public:
35:   // Http::StreamFilterBase
36:   void onDestroy() override {}
37: 
38:   // Http::StreamEncoderFilter
39:   Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
40:     return Http::Filter1xxHeadersStatus::Continue;
41:   }
42:   Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap&, bool) override {
43:     return Http::FilterHeadersStatus::Continue;
44:   }
45:   Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
46:     return Http::FilterDataStatus::Continue;
47:   }
48:   Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
49:     return Http::FilterTrailersStatus::Continue;
50:   }
51:   Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
52:     return Http::FilterMetadataStatus::Continue;
53:   }
54:   void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override {
55:     encoder_callbacks_ = &callbacks;
56:   }
57: 
58: protected:
59:   Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
60: };
61: 
