26:     const envoy::extensions::filters::http::buffer::v3::BufferPerRoute& proto_config)
27:     : disabled_(proto_config.disabled()),
28:       max_request_bytes_(
29:           proto_config.has_buffer()
30:               ? static_cast<uint64_t>(proto_config.buffer().max_request_bytes().value())
31:               : 0) {}
32: 
33: BufferFilterConfig::BufferFilterConfig(
34:     const envoy::extensions::filters::http::buffer::v3::Buffer& proto_config)
35:     : settings_(proto_config) {}
