#include "pass_through_filter.h"

#include "envoy/registry/registry.h"
#include "envoy/server/filter_config.h"

namespace Envoy {
namespace Http {

/**
 * Factory class for the pass-through HTTP filter.
 * Creates instances of PassThroughFilter for use in the HTTP filter chain.
 */
class PassThroughFilterConfig : public Server::Configuration::NamedHttpFilterConfigFactory {
public:
  /**
   * Creates a filter factory callback from the configuration proto.
   * @param proto_config The configuration protobuf message.
   * @param stats_prefix The prefix for statistics.
