#pragma once

#include "envoy/http/filter.h"

namespace Envoy {
namespace Http {

/**
 * A minimal HTTP filter that passes all data through with Continue status.
 * Implements the StreamDecoderFilter interface by passing through all data
 * without modification.
 */
class PassThroughFilter : public StreamDecoderFilter {
public:
  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  /**
   * Called with decoded headers. Returns Continue to pass headers through the filter chain.
   */
  FilterHeadersStatus decodeHeaders(RequestHeaderMap& headers, bool end_stream) override;

  /**
   * Called with decoded data. Returns Continue to pass data through the filter chain.
   */
  FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;

  /**
   * Called with decoded trailers. Returns Continue to pass trailers through the filter chain.
   */
  FilterTrailersStatus decodeTrailers(RequestTrailerMap& trailers) override;

  /**
   * Called to initialize the filter decoder callbacks. Stores the callbacks pointer
   * for potential use by the filter.
   */
  void setDecoderFilterCallbacks(StreamDecoderFilterCallbacks& callbacks) override;

protected:
  /**
   * Stores the stream decoder filter callbacks for access by derived classes.
   */
  StreamDecoderFilterCallbacks* decoder_callbacks_{};
};

} // namespace Http
} // namespace Envoy

