namespace Envoy {
namespace Http {

/**
 * Factory class for the pass-through HTTP filter.
 * Creates instances of PassThroughFilter for use in the HTTP filter chain.
 */
class PassThroughFilterConfig : public Server::Configuration::NamedHttpFilterConfigFactory {
public:
  /**
   * Creates a filter factory callback from the configuration proto.
   * @param proto_config The configuration protobuf message.
   * @param stats_prefix The prefix for statistics.
   * @param context The factory context.
   * @return A filter factory callback.
   */
  absl::StatusOr<FilterFactoryCb>
  createFilterFactoryFromProto(const Protobuf::Message& /*proto_config*/,
                               const std::string& /*stats_prefix*/,
                               Server::Configuration::FactoryContext& /*context*/) override {
    return [](FilterChainFactoryCallbacks& callbacks) -> void {
      callbacks.addStreamDecoderFilter(
          std::make_shared<PassThroughFilter>());
    };
  }

  /**
   * Returns the name of the filter.
   * @return The filter name: "envoy.filters.http.pass_through"
   */
  std::string name() const override {
    return "envoy.filters.http.pass_through";
  }

  /**
   * Creates an empty configuration proto for this filter.
   * @return An empty protobuf message.
   */
  ProtobufTypes::MessagePtr createEmptyConfigProto() override {
    return std::make_unique<Protobuf::Struct>();
  }
};

