 * Static registration for the pass-through HTTP filter.
 * Registers the PassThroughFilterConfig factory with the filter registry.
 */
REGISTER_FACTORY(PassThroughFilterConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace Http
